ico_qr_code_screen__blocking_disclaimer_main_content__text = TextObject(bs_BA="Ograničeno rukovanje u toku vožnje.", cs_CZ="Omezená obsluha během jízdy.", da_DK="Begrænset betjening under kørsel.", de_DE="Eingeschränkte Bedienung während der Fahrt.", el_GR="Περιορισμένος χειρισμός κατά τη διάρκεια της οδήγησης.", en_GB="For your safety, limited operation while driving.", es_ES="Manejo limitado durante la marcha.", fi_FI="Rajoitettu käyttö ajon aikana.", fr_FR="Utilisation restreinte pendant la conduite.", hr_HR="Ograničeno rukovanje tijekom vožnje.", hu_HU="Korlátozott használat menet közben.", it_IT="Utilizzo limitato durante la marcia.", nl_NL="Beperkte bediening tijdens het rijden.", no_NO="Betjening er begrenset under kjøring.", pl_PL="Ograniczona obsługa podczas jazdy.", pt_PT="Acionamento com restrições durante a circulação.", ro_RO="Operare limitată în timpul deplasării.", ru_RU="Во время движения управление ограничено.", sk_SK="Obmedzená obsluha počas jazdy.", sl_SI="Omejeno upravljanje med vožnjo.", sr_RS="Ograničeno rukovanje u toku vožnje.", sv_SE="Begränsad användning under körning.", tr_TR="Sürüş sırasında sınırlı kullanım.", uk_UA="Під час руху керування обмежено.")
ico_qr_code_screen__main_content__text = TextObject(bs_BA="Skenirajte QR kod za povezivanje nalogom e-pošte.\n\nAlternativno Vaš nalog e-pošte možete povezati i preko\nsljedeće internet stranice: %1", cs_CZ="Naskenujte QR kód, připojte e-mailový účet.\n Můžete ho připojit také na webové stránce: %1", da_DK="Scan QR-kode for at forbinde en e-mailkonto.\n\nAlternativt kan du også forbinde en e-mailkonto\nvia følgende hjemmeside: %1", de_DE="Bitte scanne den QR-Code, um einen E-Mail-Account zu verknüpfen.\n\nAlternativ kannst du einen E-Mail-Account auch über folgende Webseite\nverknüpfen: %1", el_GR="Σαρώστε τον κωδικό QR για να συνδέσετε έναν λογαριασμό email.\n\nΕναλλακτικά, μπορείτε να συνδέσετε έναν λογαριασμό email μέσω\nτου ακόλουθου ιστότοπου: %1", en_GB="Please scan the QR code to link an e-mail account.\n\nAlternatively, you can also link an e-mail account via the\nfollowing website: %1", es_ES="Escanee el código QR para vincular una cuenta de e-mail.\n\nTambién puede vincular una cuenta de e-mail a\ntravés de la página web siguiente: %1", fi_FI="Lue QR-koodi sähköpostitilin yhdistämiseksi.\n\nVaihtoehtoisesti voit yhdistää sähköpostitilin\nmyös seuraavan verkkosivun kautta: %1", fr_FR="Veuillez scanner le code QR pour associer un compte e-mail.\n\nVous pouvez également associer un compte\ne-mail via le site Web suivant : %1", hr_HR="Skenirajte QR kod, kako biste se spojili s računom e-maila.\n\nAlternativno se s računom e-maila možete spojiti\ni preko sljedeće web stranice: %1", hu_HU="Kérünk, olvasd be a QR-kódot az e-mail fiók összekapcsolásához.\n\nAlternatív megoldásként e-mail fiókot is összekapcsolhatsz a következő\nweboldalon keresztül: %1", it_IT="Scansionare il codice QR per collegare un account e-mail.\n\nIn alternativa è possibile collegare un account\ne-mail anche tramite il seguente sito web: %1", nl_NL="Scan de QR-code om een e-mailaccount te koppelen.\n\nJe kunt ook een e-mailaccount koppelen via de volgende website:\n%1", no_NO="Skann QR-koden for å koble til en e-postkonto.\n\nDu kan også koble til en e-postkonto på følgende\nnettsted: %1", pl_PL="Zeskanuj kod QR, aby połączyć konto e-mail.\n\nAlternatywnie można również połączyć konto e-mail poprzez\nnastępującą stronę internetową: %1", pt_PT="Por favor, digitaliza o código QR para associar uma conta de e-mail.\n\nEm alternativa podes também associar uma conta de e-mail através da\nseguinte página Web: %1", ro_RO="Scanaţi codul QR, pentru a asocia un cont E-mail.\n\nAlternativ puteţi asocia un cont E-mail şi prin următoarea\npagină web: %1", ru_RU="Отсканируйте QR-код для привязки учетной записи электронной почты.\n\nКроме того, привязать учетную запись электронной почты можно на сайте:\n%1", sk_SK="Prosím, naskenujte QR kód na prepojenie e-mailového účtu.\n\nPrípadne môžete prepojiť e-mailový účet prostredníctvom\nnasledujúcej webovej stránky: %1", sl_SI="Za povezavo e-poštnega računa skenirajte QR-kodo.\n\nE-poštni račun lahko povežete tudi preko sledeče\nspletne strani: %1", sr_RS="Skenirajte QR kod za povezivanje naloga e-pošte.\n\nAlternativno, nalog e-pošte možete da povežete i preko\nsledeće internet stranice: %1", sv_SE="Skanna QR-koden för att koppla ett e-postkonto.\n\nAlternativt kan du koppla ett e-postkonto på följande\nhemsida: %1", tr_TR="Bir e-posta hesabını bağlamak için lütfen QR kodunu tara.\n\nAlternatif olarak, aşağıdaki web sitesi üzerinden\nde bir e-posta hesabını bağlayabilirsin: %1", uk_UA="Відскануйте QR-код, щоб прив'язати обліковий запис електронної пошти.\n\nКрім того, ви також можете прив'язати обліковий запис електронної пошти\nна наступному веб-сайті: %1")
